queries.sparql:
PREFIX : <http://ambrosia.example.org/hospitality#>
PREFIX p: <http://ambrosia.example.org/hospitality/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?servicename WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasServices ?child ; p:hasHotels ?parent . } GROUP BY ?child }
  ?child p:ServiceName ?servicename .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Hotels } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/hospitality#>
PREFIX p: <http://ambrosia.example.org/hospitality/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?servicename WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasServices ?child ; p:hasHotels ?parent . } GROUP BY ?child }
  ?child p:ServiceName ?servicename .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Hotels } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?name ?servicename WHERE {
  ?hotels_services a :Hotels_Services .
  ?services a :Services .
  ?hotels_services p:hasServices ?services .
  ?hotels a :Hotels .
  ?hotels_services p:hasHotels ?hotels .
  ?hotels p:name ?name .
  ?services p:ServiceName ?servicename .
} }
}
